text:
My patch was incomplete, because that lacks a lock.
Following patch  will be correct.

--- sys/compat/linux/linux_socket.c     26 Oct 2001 23:10:08 -0000      1.30
+++ sys/compat/linux/linux_socket.c     17 Nov 2001 18:27:20 -0000
@@ -416,7 +416,7 @@
                int namelen;
        } */ bsd_args;
        struct socket *so;
-       struct file *fp;
+       unsigned int flag;
        int error;

 #ifdef __alpha__
@@ -438,17 +438,20 @@
         * when on a non-blocking socket. Instead it returns the
         * error getsockopt(SOL_SOCKET, SO_ERROR) would return on BSD.
         */
-       error = holdsock(td->td_proc->p_fd, linux_args.s, &fp);
-       if (error)
+       mtx_lock(&Giant);
+       error = fgetsock(td, linux_args.s, &so, &flag);
+       if (error) {
+               mtx_unlock(&Giant);
                return (error);
+       }
        error = EISCONN;
-       if (fp->f_flag & FNONBLOCK) {
-               so = (struct socket *)fp->f_data;
+       if (flag & FNONBLOCK) {
                if (so->so_emuldata == 0)
                        error = so->so_error;
                so->so_emuldata = (void *)1;
        }
-       fdrop(fp, td);
+       fputsock(so);
+       mtx_unlock(&Giant);
        return (error);
 }
